// ─── Parse Telegram message & buffer album photos ────────────────────────
const trigger = $('Webhook Trigger').first();
const body = trigger.json.body;
const msg = body.message || {};
const text = (msg.text || msg.caption || '').trim();
const chatId = msg.chat?.id;
const msgId = msg.message_id;
const mediaGroupId = msg.media_group_id || null;

const OPENCODE_URL = 'http://opencode-proxy:3284';

// ─── Buffer album photos ─────────────────────────────────────────
if (mediaGroupId) {
  const photos = msg.photo || [];
  let fileId = null;
  if (photos.length > 0) fileId = photos[photos.length - 1].file_id;
  if (msg.document && msg.document.mime_type && msg.document.mime_type.startsWith('image/')) {
    fileId = msg.document.file_id;
  }
  if (fileId) {
    try {
      await this.helpers.httpRequest({
        method: 'POST',
        url: `${OPENCODE_URL}/media-group/add`,
        body: { mediaGroupId, fileId },
        json: true
      });
    } catch (e) { /* ignore buffer errors */ }
  }
}

// ─── Extract photo file IDs (for single-photo /stock) ────────────
const photoFileIds = [];
const photos = msg.photo || [];
if (photos.length > 0) {
  photoFileIds.push(photos[photos.length - 1].file_id);
}
if (msg.document && msg.document.mime_type && msg.document.mime_type.startsWith('image/')) {
  photoFileIds.push(msg.document.file_id);
}

return [{ json: { chatId, msgId, text, mediaGroupId, photoFileIds, hasPhoto: !!(msg.photo || msg.document) } }];

// ─── Session Manager: resolve chatId → sessionId ─────────────────────────
const OPENCODE_URL = 'http://opencode-proxy:3284';
const { chatId, msgId, text, mediaGroupId, photoFileIds, hasPhoto } = $json;

let sessionId = 'none';
let responseText = '';

try {
  if (text === '/new') {
    const result = await this.helpers.httpRequest({
      method: 'POST',
      url: `${OPENCODE_URL}/session/clear`,
      body: { chatId },
      json: true
    });
    sessionId = result.sessionId || 'none';
    responseText = result.message || '새로운 대화를 시작합니다. 무엇을 도와드릴까요?';
  } else {
    const result = await this.helpers.httpRequest({
      method: 'GET',
      url: `${OPENCODE_URL}/session?chatId=${chatId}`,
      json: true
    });
    sessionId = result.sessionId || 'none';
  }
} catch (e) { /* ignore */ }

const sessionDisplay = sessionId.replace(/^ses_/, '');

return [{ json: { chatId, msgId, text, mediaGroupId, photoFileIds, hasPhoto, sessionId: sessionDisplay, responseText } }];

// ─── Route by Command or LLM Intent ──────────────────────────────────────────
const { chatId, msgId, text, mediaGroupId, photoFileIds, hasPhoto, sessionId, responseText } = $json;
const ROUTER_URL = 'http://router:3287';

const createOutput = (route, extra = {}) => [{ 
  json: { route, chatId, msgId, message: text, sessionId, photoFileIds, mediaGroupId, ...extra } 
}];

if (text && text.startsWith('/')) {
  const lower = text.toLowerCase();
  if (lower.startsWith('/stock')) return createOutput('stock', { subIntent: 'analyze' });
  if (lower.startsWith('/naverblog')) return createOutput('blog', { topic: text.replace(/^\/naverblog\s*/i, '').trim() });
  if (lower.startsWith('/mail')) {
    const parts = text.match(/\/mail\s+([^\s]+)\s+["']?(.*)["']?/i);
    const receiver = parts ? parts[1] : '';
    const query = parts ? (parts[2] || '').replace(/["']$/, '') : '';
    return createOutput('email', { receiver, query });
  }
  return createOutput('opencode', { responseText });
}

if (!text) {
  if (hasPhoto) return createOutput('stock', { subIntent: 'analyze' });
  return createOutput('opencode', { responseText: '(no text provided)' });
}

try {
  const result = await this.helpers.httpRequest({
    method: 'POST', 
    url: `${ROUTER_URL}/router/intent`, 
    body: { message: text }, 
    json: true 
  });

  // Ensure result is an object
  const routerResult = (typeof result === 'string') ? JSON.parse(result) : result;
  console.log('[n8n Router] Raw Result:', JSON.stringify(routerResult));

  const intent = routerResult.intent || 'opencode';
  const subIntent = routerResult.subIntent || null;
  const routeMap = { 'blog': 'blog', 'email': 'email', 'stock': 'stock', 'qa': 'opencode', 'search': 'opencode', 'general': 'opencode' };
  const finalRoute = routeMap[intent] || 'opencode';

  const extra = { subIntent, routerConfidence: routerResult.confidence };
  if (finalRoute === 'blog') extra.topic = text;
  if (finalRoute === 'email') extra.query = text;

  console.log(`[n8n Router] Result: ${finalRoute} (${intent})`);
  return createOutput(finalRoute, extra);
} catch (e) {
  console.error('[n8n Router] Error:', e.message);
  return createOutput('opencode', { responseText });
}

