// ─── Run OpenCode ────────────────────────────────────────────────────────────
const OPENCODE_URL = 'http://opencode-proxy:3284';
const TIMEOUT = 300000;

// Try to get data from the 'Route by Command' node
const routeNode = $('Route by Command');
const routeData = routeNode.first() ? routeNode.first().json : $json;

const message = routeData.message || '';
const chatId  = routeData.chatId;
const msgId   = routeData.msgId;
const sessionIdDisplay = routeData.sessionId || 'none';

console.log('[Run OpenCode] Executing with message:', message.slice(0, 50));

// Handle /new system response
if (routeData.responseText) {
  const formattedText = `✨ <b>System Message:</b>\n🏷️ <b>Session:</b> <code>${sessionIdDisplay}</code>\n\n${routeData.responseText}`;
  return [{ json: { chatId, msgId, formattedText, sessionId: sessionIdDisplay } }];
}

if (!message) {
  return [{ json: { chatId, msgId, formattedText: '(메시지가 비어있습니다)', sessionId: sessionIdDisplay } }];
}

function escapeHTML(str) {
  return str.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
}

try {
  const result = await this.helpers.httpRequest({
    method: 'POST',
    url: `${OPENCODE_URL}/run`,
    body: { prompt: message, chatId: String(chatId) },
    json: true,
    timeout: TIMEOUT
  });

  const model = result.model || 'OpenCode';
  let text = result.text || '(no output)';

  if (text.length > 3900) {
    text = text.slice(0, 3900) + "\n\n... (Truncated)";
  }

  const returnedSession = result.sessionId ? result.sessionId.replace(/^ses_/, '') : sessionIdDisplay;
  const formattedText = `🤖 <b>Model:</b> <code>${escapeHTML(model)}</code> \n🏷️ <b>Session:</b> <code>${escapeHTML(returnedSession)}</code>\n\n${escapeHTML(text)}`;

  return [{ json: { chatId, msgId, formattedText, sessionId: returnedSession } }];
} catch (e) {
  const errMsg = (e.message || '').slice(0, 500);
  const formattedText = `❌ <b>오류:</b> \n🏷️ <b>Session:</b> <code>${escapeHTML(sessionIdDisplay)}</code>\n\n<pre>${escapeHTML(errMsg)}</pre>`;
  return [{ json: { chatId, msgId, formattedText, sessionId: sessionIdDisplay } }];
}

