// ─── Generate & Send AI Email ────────────────────────────────────────────
const OPENCODE_URL = 'http://opencode-proxy:3284';
const routeData = $('Route by Command').first().json;
const { chatId, msgId, sessionId, receiver, query } = routeData;

if (!receiver || !query) {
  throw new Error('이메일 주소나 요청 내용이 비어있습니다. 사용법: /mail recipient@example.com "내용"');
}

try {
  // 1. Generate Email Content
  const genResult = await this.helpers.httpRequest({
    method: 'POST',
    url: `${OPENCODE_URL}/generate-email`,
    body: { query, chatId: String(chatId) },
    json: true,
    timeout: 120000
  });

  if (!genResult.ok) throw new Error(genResult.text || '이메일 생성 실패');

  // 2. Send Email via SMTP
  const sendResult = await this.helpers.httpRequest({
    method: 'POST',
    url: `${OPENCODE_URL}/send-email`,
    body: { 
      to: receiver, 
      subject: genResult.subject, 
      body: genResult.body 
    },
    json: true,
    timeout: 60000
  });

  if (!sendResult.ok) throw new Error(sendResult.text || '이메일 발송 실패');

  const formattedText = `✅ <b>이메일 발송 성공!</b>\n🏷️ <b>Session:</b> <code>${sessionId || 'none'}</code> (Model: ${genResult.model})\n\n📬 <b>To:</b> ${receiver}\n📌 <b>Subject:</b> ${genResult.subject}\n\n${genResult.body.slice(0, 500)}${genResult.body.length > 500 ? '...' : ''}`;

  return [{ json: { chatId, msgId, formattedText, sessionId } }];
} catch (e) {
  const errMsg = (e.response && e.response.data && e.response.data.text) 
    ? e.response.data.text 
    : (e.response && e.response.data && e.response.data.error) 
      ? (typeof e.response.data.error === 'string' ? e.response.data.error : JSON.stringify(e.response.data.error))
      : e.message;
  const formattedText = `❌ <b>이메일 오류:</b>\n🏷️ <b>Session:</b> <code>${sessionId || 'none'}</code>\n\n<pre>${errMsg}</pre>`;
  return [{ json: { chatId, msgId, formattedText, sessionId } }];
}
